// ===== JS工具库 =====
// HTTP请求封装
function httpGet(url, headers) {
  const resp = fetch(url, { headers: headers || {} });
  return resp;
}

function httpPost(url, body, headers) {
  const resp = fetch(url, { method: 'POST', body: body, headers: headers || {} });
  return resp;
}

// JSON解析
function parseJson(text) {
  return JSON.parse(text);
}

// HTML解析辅助
function matchAll(regex, text) {
  const results = [];
  let match;
  while ((match = regex.exec(text)) !== null) {
    results.push(match[1] || match[0]);
  }
  return results;
}

// 搜索结果解析
function parseSearchList(html) {
  const results = [];
  const items = html.match(/<li[^>]*class="book-item"[^>]*>[\s\S]*?<\/li>/g) || [];
  for (const item of items) {
    results.push({
      name: item.match(/<h3[^>]*>([^<]*)<\/h3>/)?.[1]?.trim() || '',
      author: item.match(/作者[：:]\s*([^<]*)/)?.[1]?.trim() || '',
      bookUrl: item.match(/href="([^"]+)"/)?.[1] || '',
      coverUrl: item.match(/src="([^"]+\.(?:jpg|png|webp))"/)?.[1] || '',
      intro: item.match(/<p[^>]*class="intro"[^>]*>([\s\S]*?)<\/p>/)?.[1]?.replace(/<[^>]*>/g, '')?.trim() || '',
      kind: item.match(/<span[^>]*class="category"[^>]*>([^<]*)<\/span>/)?.[1]?.trim() || '',
      lastChapter: item.match(/<a[^>]*class="chapter"[^>]*>([^<]*)<\/a>/)?.[1]?.trim() || ''
    });
  }
  return JSON.stringify(results);
}

// 详情页解析
function parseBookInfo(html) {
  const info = {};
  info.name = html.match(/<h1[^>]*>([^<]*)<\/h1>/)?.[1]?.trim() || '';
  info.author = html.match(/作者[：:]\s*([^<]*)/)?.[1]?.trim() || '';
  info.intro = html.match(/<div[^>]*class="intro"[^>]*>([\s\S]*?)<\/div>/)?.[1]?.replace(/<[^>]*>/g, '')?.trim() || '';
  info.coverUrl = html.match(/<img[^>]*class="cover"[^>]*src="([^"]*)"/)?.[1] || html.match(/<img[^>]*src="([^"]*\.(?:jpg|png|webp))"[^>]*class="cover"/)?.[1] || '';
  info.tocUrl = html.match(/<a[^>]*class="read"[^>]*href="([^"]*)"/)?.[1] || '';
  info.kind = html.match(/<span[^>]*class="category"[^>]*>([^<]*)<\/span>/)?.[1]?.trim() || '';
  info.lastChapter = html.match(/<span[^>]*class="last-chapter"[^>]*>([^<]*)<\/span>/)?.[1]?.trim() || '';
  info.wordCount = html.match(/<span[^>]*class="word-count"[^>]*>([^<]*)<\/span>/)?.[1]?.trim() || '';
  return JSON.stringify(info);
}

// 目录解析
function parseChapterList(html) {
  const chapters = [];
  const items = html.match(/<li[^>]*>[\s\S]*?<\/li>/g) || [];
  for (const item of items) {
    chapters.push({
      name: item.match(/<a[^>]*>([^<]*)<\/a>/)?.[1]?.trim() || '',
      url: item.match(/href="([^"]+)"/)?.[1] || '',
      isVolume: item.match(/<span[^>]*class="volume"/)?.[0] ? 'true' : ''
    });
  }
  return JSON.stringify(chapters);
}

// 正文解析
function parseContent(html) {
  let content = html.match(/<div[^>]*class="content"[^>]*>([\s\S]*?)<\/div>/)?.[1] || '';
  // 清理script和style标签
  content = content.replace(/<script[^>]*>[\s\S]*?<\/script>/g, '');
  content = content.replace(/<style[^>]*>[\s\S]*?<\/style>/g, '');
  content = content.trim();
  return content;
}
